import { createClient } from '@vex_dev/sdk';

const vex = createClient({
  projectId: process.env.VEX_PROJECT_ID!,
  secret: process.env.VEX_SECRET!,
});

export default defineN8nWebhook({
  path: '/chatbot',
  method: 'POST',
  async handler(req, res) {
    const { message, conversationId } = req.body;

    // Store raw input for Vex verification later
    const inputSpan = await vex.span('chatbot.input', {
      input: { message, conversationId },
      conversationId
    });

    return res.json({
      workflowData: [{ json: { message, conversationId, vexSpanId: inputSpan.id } }]
    });
  }
});

// n8n AI Agent Node configuration
const agentConfig = {
  model: 'gpt-4o-mini',
  systemPrompt: `You are an intent classifier for a customer support chatbot.
Classify the user message into one of: GREETING, QUERY, COMPLAINT, ESCALATION.
Respond ONLY with JSON: {"intent": "QUERY", "confidence": 0.95}`
};

// Pass to next node
const intentOutput = $input.all()[0].json;

// Vex verification checkpoint
const verification = await $http.request({
  method: 'POST',
  url: 'https://api.vex.dev/v1/verify',
  headers: {
    'Authorization': `Bearer ${$env.VEX_SECRET}`,
    'Content-Type': 'application/json'
  },
  body: {
    spanId: intentOutput.vexSpanId,
    checks: ['json_schema'],
    schema: {
      type: 'object',
      properties: {
        intent: { type: 'string', enum: ['GREETING', 'QUERY', 'COMPLAINT', 'ESCALATION'] },
        confidence: { type: 'number', minimum: 0, maximum: 1 }
      }
    }
  }
});

const ragAgentConfig = {
  model: 'gpt-4o',
  systemPrompt: `You are a helpful support agent. Use ONLY the provided context.
Context: {{ $json.retrievedDocs }}
User: {{ $json.message }}
Respond conversationally but factually.`,
  tools: [
    {
      type: 'retrieval',
      name: 'knowledge_base',
      description: 'Search support documentation'
    }
  ]
};

// After RAG execution
const ragOutput = $input.all()[0].json.response;

// Vex hallucination + accuracy check
return {
  ragResponse: ragOutput,
  vexPayload: {
    spanId: $json.vexSpanId,
    checks: ['hallucination_detection', 'response_accuracy'],
    context: $json.retrievedDocs,
    response: ragOutput,
    conversationId: $json.conversationId
  }
};

// Memory Window Node + Vex Coherence Check
const memoryConfig = {
  windowSize: 10,
  memoryKey: 'chat_history',
  conversationId: $json.conversationId
};

const fullContext = {
  history: $json.chatHistory,
  currentMessage: $json.message,
  ragContext: $json.retrievedDocs
};

// Verify context coherence before final response
const coherenceCheck = await $http.request({
  url: 'https://api.vex.dev/v1/verify',
  method: 'POST',
  body: {
    spanId: $json.vexSpanId,
    checks: ['conversation_coherence'],
    context: {
      history: fullContext.history.slice(-5),
      current: fullContext.currentMessage
    },
    maxTokens: 4000
  }
});

return {
  verifiedContext: coherenceCheck.data.pass ? fullContext : null,
  conversationId: $json.conversationId
};

