// Vex Webhook Node Configuration
const vexWebhookNode = {
  resource: 'httpRequest',
  operation: 'post',
  url: 'https://api.vex.dev/v1/verify',
  headers: {
    Authorization: `Bearer {{$secrets.VEX_SECRET}}`,
    'Content-Type': 'application/json'
  },
  body: {
    spanId: '={{$json.vexSpanId}}',
    checks: [
      'response_accuracy',
      'conversation_coherence',
      'safety_filtering',
      'pii_protection',
      'hallucination_detection'
    ],
    input: '={{$json.message}}',
    output: '={{$json.aiResponse}}',
    conversationId: '={{$json.conversationId}}',
    riskProfile: 'high'
  },
  options: {
    timeout: 5000,
    responseFormat: 'json'
  }
};

// IF Node after Vex Webhook
const routingConditions = [
  {
    conditions: {
      options: { caseSensitive: true, leftValue: '', typeValidation: 'strict' },
      conditions: [
        {
          id: 'v1',
          leftValue: '={{$json.pass}}',
          rightValue: false,
          operator: { type: 'boolean', operation: 'equals' }
        }
      ],
      combinators: []
    },
    name: 'Vex Failed - Route to Fallback'
  },
  {
    name: 'Vex Passed - Continue to Response'
  }
];

// Fallback branch
const fallbackResponse = {
  respondToWebhook: {
    respondWith: 'text',
    responseBody: 'I apologize, let me get a human to help you. One moment...',
    options: {}
  }
};

// Final Vex span close before webhook response
const finalizeSpan = await $http.request({
  method: 'POST',
  url: `https://api.vex.dev/v1/spans/{{$json.vexSpanId}}/close`,
  headers: {
    'Authorization': `Bearer {{$secrets.VEX_SECRET}}`,
    'Content-Type': 'application/json'
  },
  body: {
    metrics: {
      responseTime: Date.now() - $json.conversationStart,
      tokenUsage: $json.totalTokens,
      vexScore: $json.vexResult.score
    },
    finalOutput: $json.finalResponse,
    status: 'success'
  }
});

// Safe webhook response
return {
  respondToWebhook: true,
  responseData: {
    response: $json.finalResponse,
    conversationId: $json.conversationId,
    vexPassed: $json.vexResult.pass
  }
};
